const msg = $input.first().json;
const text = msg?.message?.text || '';
const chatId = msg?.message?.chat?.id;
const from = msg?.message?.from;
const userName = from?.username || from?.first_name || 'Desconocido';
const userId = from?.id?.toString() || 'unknown';
const messageId = msg?.message?.message_id;
const now = new Date();

if (!text || text.startsWith('/')) {
  return [{ json: { skip: true, chatId, text, userName, isCommand: text.startsWith('/'), command: text } }];
}

return [{
  json: {
    skip: false,
    chatId,
    userName,
    userId,
    messageId,
    text,
    timestamp: now.toISOString(),
    date: now.toLocaleDateString('es-ES'),
    time: now.toLocaleTimeString('es-ES')
  }
}];

// Construir el bloque de few-shot examples desde Supabase
const trainingRows = $input.first().json;
const incidenciaData = $('Extraer mensaje').first().json;

let fewShotBlock = '';

if (Array.isArray(trainingRows) && trainingRows.length > 0) {
  fewShotBlock = '\n\n=== EJEMPLOS DE ENTRENAMIENTO (few-shot) ===\n';

  // Agrupar por categoría
  const byGroup = {};
  trainingRows.forEach(row => {
    if (!byGroup[row.categoria]) byGroup[row.categoria] = [];
    byGroup[row.categoria].push(row);
  });

  Object.entries(byGroup).forEach(([cat, examples]) => {
    fewShotBlock += `\n[${cat}]\n`;
    examples.forEach(ex => {
      fewShotBlock += `  Ejemplo: "${ex.texto_ejemplo}"\n`;
      if (ex.razon_ejemplo) fewShotBlock += `  Razón: ${ex.razon_ejemplo}\n`;
    });
  });

  fewShotBlock += '\n=== FIN EJEMPLOS ===';
}

return [{
  json: {
    ...incidenciaData,
    fewShotBlock,
    trainingCount: trainingRows?.length || 0
  }
}];

const response = $input.first().json;
const prevData = $('Construir prompt con ejemplos').first().json;

let rawText = '';
try {
  rawText = response.content[0].text;
} catch(e) {
  rawText = '{}';
}

let parsed;
try {
  const clean = rawText.replace(/```json|```/g, '').trim();
  parsed = JSON.parse(clean);
} catch(e) {
  parsed = {
    categoria: 'ERROR - No clasificado',
    numero_grupo: 0,
    prioridad: 'MEDIA',
    confianza: 'BAJA',
    razon_clasificacion: 'Error al parsear respuesta del agente: ' + rawText.substring(0, 300),
    palabras_clave: [],
    resumen_incidencia: prevData.text.substring(0, 150),
    accion_recomendada: 'Revisión manual necesaria',
    requiere_revision_humana: true
  };
}

const emojis = { 1:'🎬', 2:'👁️', 3:'✍️', 4:'⚙️', 5:'🎙️', 6:'📁', 7:'🏛️', 8:'👤', 9:'🖥️', 0:'❓' };
const prioEmojis = { 'ALTA':'🔴', 'MEDIA':'🟡', 'BAJA':'🟢' };
const confEmojis = { 'ALTA':'✅', 'MEDIA':'⚠️', 'BAJA':'🔸' };

const grupoEmoji = emojis[parsed.numero_grupo] || '❓';
const prioEmoji = prioEmojis[parsed.prioridad] || '⚪';
const confEmoji = confEmojis[parsed.confianza] || '❓';

const telegramMsg = 
  `${grupoEmoji} *CLASIFICACIÓN DE INCIDENCIA*\n\n` +
  `📋 *Categoría:* ${parsed.categoria}\n` +
  `${prioEmoji} *Prioridad:* ${parsed.prioridad}\n` +
  `${confEmoji} *Confianza IA:* ${parsed.confianza}\n\n` +
  `📝 *Resumen:*\n${parsed.resumen_incidencia}\n\n` +
  `🔍 *¿Por qué esta categoría?*\n${parsed.razon_clasificacion}\n\n` +
  `🛠️ *Acción recomendada:*\n${parsed.accion_recomendada}\n\n` +
  `🏷️ *Palabras clave:* ${(parsed.palabras_clave || []).join(', ')}` +
  (parsed.requiere_revision_humana ? '\n\n⚠️ _Este caso requiere revisión humana_' : '') +
  `\n\n🆔 _ID: ${prevData.timestamp}_`;

return [{
  json: {
    ...prevData,
    clasificacion: parsed,
    telegramMsg,
    // Campos para Supabase
    sb_texto: prevData.text,
    sb_usuario: prevData.userName,
    sb_chat_id: prevData.chatId?.toString(),
    sb_categoria: parsed.categoria,
    sb_numero_grupo: parsed.numero_grupo,
    sb_prioridad: parsed.prioridad,
    sb_confianza: parsed.confianza,
    sb_razon: parsed.razon_clasificacion,
    sb_palabras_clave: parsed.palabras_clave || [],
    sb_resumen: parsed.resumen_incidencia,
    sb_accion: parsed.accion_recomendada,
    sb_revision: parsed.requiere_revision_humana,
    sb_ejemplos_usados: prevData.trainingCount || 0,
    sb_timestamp: prevData.timestamp
  }
}];

// Extraer el ID del registro recién insertado para el informe
const inserted = $input.first().json;
const prevData = $('Parsear respuesta Claude').first().json;

const recordId = Array.isArray(inserted) ? inserted[0]?.id : inserted?.id;

return [{
  json: {
    ...prevData,
    supabase_record_id: recordId || null
  }
}];

